MERGE INTO CONSULTAS FIN USING (SELECT '002659CotizacionesFacturacionArrendamiento' INFORME ,TO_CLOB(q'[SELECT SF_COTIZACION.NUMERO, SF_COTIZACION.TIPO, SF_COTIZACION.TIEMPO_COTIZADO, SF_COTIZACION.FECHA_SOLICITUD,
SF_COTIZACION.FECHA_VENCIMIENTO, TRIM(SF_COTIZACION.TERCERO) TERCERO, 
CONCAT(CONCAT(CONCAT(TERCERO.NOMBRE1,CONCAT( ' ' , NVL(TERCERO.NOMBRE2, ''))), CONCAT(' ',TERCERO.APELLIDO1)), CONCAT(' ',TERCERO.APELLIDO2)) NOMBRE,
SF_DETALLE_COTIZACION.INMUEBLE, CASE SF_DETALLE_COTIZACION.TIPO_INMUEBLE WHEN 1 THEN 'Local'           WHEN 2 THEN 'Mezzanine'           WHEN 3 THEN 'Bodega'           WHEN 4 THEN 'SÃ³tano'            WHEN 5 THEN 'Oficina'           WHEN 6 THEN 'Piso'           WHEN 7 THEN 'Casa'           WHEN 8 THEN 'Lote'           WHEN 9 THEN 'Plazoleta'           WHEN 10 THEN 'Galeria Bochica'           WHEN 11 THEN 'Edificio'           WHEN 12 THEN 'Terraza'           WHEN 13 THEN 'BaÃ±o'           WHEN 14 THEN 'Pasillo'           WHEN 15 THEN 'Espacio' END TIPO_INMUEBLE,
CASE SF_COTIZACION.EDIFICIO WHEN  1 THEN 'Ascensores'               WHEN 2 THEN 'Pedregal'               WHEN 3 THEN 'RTN'               WHEN 4 THEN 'Bachue'               WHEN 5 THEN 'RTS'               WHEN 6 THEN 'Bochica'               WHEN 7 THEN '0001'               WHEN 8 THEN '0003' END EDIFICIO, SF_COTIZACION.PORC_FONDO,
CASE SF_COTIZACION.ESTADO WHEN 1 THEN 'Creada' WHEN 2 THEN 'En proceso' WHEN 3 THEN 'Aprobada' WHEN 4 THEN 'Rechazada' WHEN 5 THEN 'Cancelada' END ESTADO,
IMF.DENOMINACION, IMF.AREA TOTAL_AREA, SF_CONCEPTOS.NOMBRE NOMBRE_CONCEPTO,
SF_DETALLE_COTIZACION.VALOR_UNITARIO, SF_DETALLE_COTIZACION.VALOR_IVA,
((SF_DETALLE_COTIZACION.CANTIDAD * SF_DETALLE_COTIZACION.VALOR_UNITARIO) + SF_DETALLE_COTIZACION.VALOR_IVA) TOTAL
FROM SF_COTIZACION
INNER JOIN TERCERO ON
(SF_COTIZACION.TERCERO = TERCERO.NIT
AND TERCERO.COMPANIA = SF_COTIZACION.COMPANIA)
INNER JOIN SF_DETALLE_COTIZACION ON
(SF_COTIZACION.COMPANIA = SF_DETALLE_COTIZACION.COMPANIA
AND SF_COTIZACION.NUMERO = SF_DETALLE_COTIZACION.NUMERO)
INNER JOIN INMUEBLE_FACTURACION IMF ON
(SF_DETALLE_COTIZACION.COMPANIA = IMF.COMPANIA
AND SF_DETALLE_COTIZACION.INMUEBLE = IMF.CODIGOINMUEBLE)
LEFT JOIN SF_CONCEPTOS ON
(SF_DETALLE_COTIZACION.COMPANIA = SF_CONCEPTOS.COMPANIA
AND SF_DETALLE_COTIZACION.CONCEPTO = SF_CONCEPTOS.CODIGO
AND SF_CONCEPTOS.TIPOCOBRO = 's$tipoCobro$s')
WHERE SF_COTIZACION.COMPANIA = 's$compania$s'
AND TRIM(SF_COTIZACION.TERCERO) BETWEEN 's$terceroInicial$s' AND 's$terceroFinal$s'
AND SF_COTIZACION.FECHA_SOLICITUD BETWEEN 's$fechaInicial$s' AND 's$fechaFinal$s'
s$estadoFiltro$s
ORDER BY TERCERO.NIT]') CONSULTA, 69 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'mrosero' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);